#!/usr/bin/env node
/**
 * BFS `import` closure from configured Init-only root modules (no Mathlib).
 *
 * Configuration: `scripts/init-only-import-closure.json` (array `roots` with `module` names).
 *
 * Run from `open-source/gnosis`: `node scripts/validate-init-only-import-closure.mjs`
 * Optional: `CONFIG=/path/to/config.json node scripts/validate-init-only-import-closure.mjs`
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const pkgRoot = path.resolve(__dirname, '..');

const configPath = process.env.CONFIG
  ? path.resolve(process.cwd(), process.env.CONFIG)
  : path.join(__dirname, 'init-only-import-closure.json');

function loadConfig() {
  if (!fs.existsSync(configPath)) {
    console.error(`validate-init-only-import-closure: missing config ${path.relative(pkgRoot, configPath)}`);
    process.exit(2);
  }
  const raw = fs.readFileSync(configPath, 'utf8');
  const cfg = JSON.parse(raw);
  if (!cfg.leanSrcRelative || typeof cfg.leanSrcRelative !== 'string') {
    console.error('validate-init-only-import-closure: config must set leanSrcRelative (string)');
    process.exit(2);
  }
  if (!Array.isArray(cfg.roots) || cfg.roots.length === 0) {
    console.error('validate-init-only-import-closure: config.roots must be a non-empty array');
    process.exit(2);
  }
  return cfg;
}

function resolveModule(leanLean, importPath) {
  const parts = importPath.split('.');
  return path.join(leanLean, ...parts) + '.lean';
}

function mathlibLine(trimmed) {
  return trimmed.startsWith('import Mathlib') || /^import\s+Mathlib\./.test(trimmed);
}

/**
 * @param {string} leanLean
 * @param {string} entryFile
 * @returns {{ seen: Set<string>, mathlibViolations: Array<{ file: string, line: string }> }}
 */
function closureFromEntry(leanLean, entryFile) {
  const queue = [entryFile];
  const seen = new Set();
  const mathlibViolations = [];

  while (queue.length > 0) {
    const file = queue.shift();
    if (seen.has(file)) continue;
    seen.add(file);
    if (!fs.existsSync(file)) {
      console.error(`validate-init-only-import-closure: missing file ${path.relative(pkgRoot, file)}`);
      process.exit(2);
    }
    const text = fs.readFileSync(file, 'utf8');
    for (const line of text.split('\n')) {
      const trimmed = line.trim();
      if (mathlibLine(trimmed)) {
        mathlibViolations.push({ file, line: trimmed });
      }
      const m = trimmed.match(/^import\s+(\S+)/);
      if (!m) continue;
      const imp = m[1];
      if (imp === 'Init' || imp.startsWith('Std')) continue;
      if (imp === 'Mathlib' || imp.startsWith('Mathlib.')) continue;
      const target = resolveModule(leanLean, imp);
      if (fs.existsSync(target)) queue.push(target);
    }
  }
  return { seen, mathlibViolations };
}

function main() {
  const cfg = loadConfig();
  const leanLean = path.join(pkgRoot, cfg.leanSrcRelative);

  const allViolations = [];

  for (const root of cfg.roots) {
    const mod = root.module;
    if (!mod || typeof mod !== 'string') {
      console.error('validate-init-only-import-closure: each root must have a module string');
      process.exit(2);
    }
    const entry = resolveModule(leanLean, mod);
    const { seen, mathlibViolations } = closureFromEntry(leanLean, entry);
    for (const v of mathlibViolations) {
      allViolations.push({ root: mod, ...v });
    }
    const label = root.description ? `${mod} (${root.description})` : mod;
    if (mathlibViolations.length === 0) {
      console.log(
        `validate-init-only-import-closure: OK root ${label} — ${seen.size} files in closure, no Mathlib`,
      );
    }
  }

  if (allViolations.length > 0) {
    console.error('validate-init-only-import-closure: Mathlib import in Init-only root closure(s):');
    for (const { root, file, line } of allViolations) {
      console.error(`  [root ${root}] ${path.relative(pkgRoot, file)}: ${line}`);
    }
    process.exit(1);
  }

  console.log(`validate-init-only-import-closure: all ${cfg.roots.length} Init-only root(s) passed (no Mathlib in any closure).`);
}

main();
